  const date = dateOnly(value);
  if (!date) return false;
  const start = dateOnly(startDate);
  const end = dateOnly(endDate);
  if (start && date < start) return false;
  if (end) {
    end.setHours(23, 59, 59, 999);
    if (date > end) return false;
  }
  return true;
}

